const items = $input.all();
const results = [];
const SKIP_REL = /rel=['"](?:self|hub)['"]/ ;
for (const item of items) {
  const xml = (typeof item.json.body === 'string' ? item.json.body : '') ||
               (typeof item.json.data === 'string' ? item.json.data : '');
  if (!xml) continue;
  const matches = [...xml.matchAll(/<item[^>]*>[\s\S]*?<\/item>/gi)];
  for (const match of matches) {
    const block = match[0];
    const titleMatch = block.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s);
    // Try plain <link>...</link> first
    let link = '';
    const plainLink = block.match(/<link>([^<]+)<\/link>/);
    if (plainLink) {
      link = plainLink[1].trim();
    } else {
      // Try self-closing Atom-style <link .../> but skip rel=self and rel=hub
      const allAtomLinks = [...block.matchAll(/<link([^>]*)\/>/gi)];
      for (const al of allAtomLinks) {
        const attrs = al[1];
        if (SKIP_REL.test(attrs)) continue;
        const hrefMatch = attrs.match(/href=['"]([^'"]+)['"]/);
        if (hrefMatch) { link = hrefMatch[1].trim(); break; }
      }
    }
    let title = titleMatch ? titleMatch[1].replace(/<!\[CDATA\[/g,'').replace(/\]\]>/g,'').trim() : '';
    if (title && link) {
      results.push({ json: { source: 'TechCrunch', title, link } });
    }
  }
}
return results;

