const items = $input.all();
const results = [];
const SKIP_REL = /rel=['"](?:self|hub)['"]/ ;
for (const item of items) {
  const xml = (typeof item.json.body === 'string' ? item.json.body : '') ||
               (typeof item.json.data === 'string' ? item.json.data : '');
  if (!xml) continue;
  let matches = [...xml.matchAll(/<item[^>]*>[\s\S]*?<\/item>/gi)];
  if (matches.length === 0) {
    matches = [...xml.matchAll(/<entry[^>]*>[\s\S]*?<\/entry>/gi)];
  }
  for (const match of matches) {
    const block = match[0];
    const titleMatch = block.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s);
    let link = '';
    // Prefer rel=alternate explicitly
    const alternateLinkMatch = block.match(/<link[^>]+rel=['"]alternate['"][^>]+href=['"]([^'"]+)['"][^>]*\/?>/);
    if (alternateLinkMatch) {
      link = alternateLinkMatch[1].trim();
    } else {
      // Try all self-closing link tags, skip rel=self and rel=hub
      const allAtomLinks = [...block.matchAll(/<link([^>]*)\/>/gi)];
      for (const al of allAtomLinks) {
        const attrs = al[1];
        if (SKIP_REL.test(attrs)) continue;
        const hrefMatch = attrs.match(/href=['"]([^'"]+)['"]/);
        if (hrefMatch) { link = hrefMatch[1].trim(); break; }
      }
      // Fallback: plain RSS <link>
      if (!link) {
        const plainLink = block.match(/<link>([^<]+)<\/link>/);
        if (plainLink) link = plainLink[1].trim();
      }
    }
    let title = titleMatch ? titleMatch[1].replace(/<!\[CDATA\[/g,'').replace(/\]\]>/g,'').replace(/<[^>]+>/g,'').trim() : '';
    if (title && link) {
      results.push({ json: { source: 'The Verge', title, link } });
    }
  }
}
return results;

const allItems = $input.all();

const grouped = {
  TechCrunch: [],
  'Hacker News': [],
  'The Verge': []
};

for (const item of allItems) {
  const source = item.json.source;
  const title = item.json.title;
  const link = item.json.link;
  if (title && link && grouped.hasOwnProperty(source)) {
    grouped[source].push({ title, link });
  }
}

const totalItems = grouped.TechCrunch.length + grouped['Hacker News'].length + grouped['The Verge'].length;

return [{
  json: {
    collectedAt: new Date().toISOString(),
    totalItems,
    sources: grouped
  }
}];
